import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.CHSDihme.js";const u=JSON.parse('{"title":"Computer Use Guide","description":"","frontmatter":{},"headers":[],"relativePath":"en/features/computer-use.md","filePath":"en/features/computer-use.md","lastUpdated":1780319135000}'),n={name:"en/features/computer-use.md"};function i(r,e,d,l,c,p){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="computer-use-guide" tabindex="-1">Computer Use Guide <a class="header-anchor" href="#computer-use-guide" aria-label="Permalink to &quot;Computer Use Guide&quot;">​</a></h1><blockquote><p><strong>Modified Version</strong>: This feature is a <strong>heavily modified version</strong> of the Computer Use (internal codename &quot;Chicago&quot;) found in the leaked Claude Code source. The official implementation relies on Anthropic&#39;s private native modules (<code>@ant/computer-use-swift</code>, <code>@ant/computer-use-input</code>) that are not publicly available. We <strong>replaced the entire underlying operation layer</strong> with a Python bridge: macOS uses <code>pyautogui</code> + <code>mss</code> + <code>pyobjc</code>, and Windows uses <code>pyautogui</code> + <code>mss</code> + <code>win32gui</code> + <code>psutil</code>.</p></blockquote><hr><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#overview">Overview</a></li><li><a href="#supported-platforms">Supported Platforms</a></li><li><a href="#how-it-works">How It Works</a></li><li><a href="#quick-start">Quick Start</a></li><li><a href="#usage">Usage</a></li><li><a href="#security">Security</a></li><li><a href="#environment-variables">Environment Variables</a></li><li><a href="#technical-architecture">Technical Architecture</a></li><li><a href="#approaches-we-tried">Approaches We Tried</a></li><li><a href="#known-limitations">Known Limitations</a></li><li><a href="#references-and-credits">References and Credits</a></li></ul><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Computer Use allows AI models to <strong>directly control your computer</strong> — taking screenshots, moving the mouse, clicking buttons, typing text, and managing application windows.</p><p>24 MCP tools are available:</p><table tabindex="0"><thead><tr><th>Category</th><th>Tools</th></tr></thead><tbody><tr><td>Screenshot</td><td><code>screenshot</code>, <code>zoom</code></td></tr><tr><td>Mouse</td><td><code>left_click</code>, <code>right_click</code>, <code>middle_click</code>, <code>double_click</code>, <code>triple_click</code>, <code>left_click_drag</code>, <code>mouse_move</code>, <code>left_mouse_down</code>, <code>left_mouse_up</code>, <code>cursor_position</code>, <code>scroll</code></td></tr><tr><td>Keyboard</td><td><code>type</code>, <code>key</code>, <code>hold_key</code></td></tr><tr><td>Apps</td><td><code>open_application</code>, <code>switch_display</code></td></tr><tr><td>Permissions</td><td><code>request_access</code>, <code>list_granted_applications</code></td></tr><tr><td>Clipboard</td><td><code>read_clipboard</code>, <code>write_clipboard</code></td></tr><tr><td>Other</td><td><code>wait</code>, <code>computer_batch</code></td></tr></tbody></table><hr><h2 id="supported-platforms" tabindex="-1">Supported Platforms <a class="header-anchor" href="#supported-platforms" aria-label="Permalink to &quot;Supported Platforms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Platform</th><th>Architecture</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td>macOS</td><td>Apple Silicon (M1/M2/M3/M4)</td><td>✅ Fully supported</td><td>Recommended</td></tr><tr><td>macOS</td><td>Intel x86_64</td><td>✅ Fully supported</td><td></td></tr><tr><td>Windows</td><td>x64</td><td>✅ Fully supported</td><td>Uses <code>win32gui</code> + <code>psutil</code> + <code>pyperclip</code> + <code>screeninfo</code> instead of macOS APIs</td></tr><tr><td>Linux</td><td>Any</td><td>⚠️ Theoretically possible</td><td>Same as above — <code>pyobjc</code> needs to be replaced with <code>wmctrl</code> + <code>xdotool</code>. Not yet adapted</td></tr></tbody></table><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ul><li><a href="https://bun.sh" target="_blank" rel="noreferrer">Bun</a> &gt;= 1.1.0</li><li>Python &gt;= 3.8 (venv and dependencies are auto-installed on first use)</li><li>macOS permissions: Accessibility + Screen Recording</li><li>Windows: no extra OS permission setup</li></ul><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Computer Use operates through a <strong>screenshot → analyze → act</strong> feedback loop:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  AI Model (Claude / any Anthropic-protocol model)   │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  1. Receives user request: &quot;open Music app&quot;         │</span></span>
<span class="line"><span>│  2. Calls screenshot tool → receives screen image   │</span></span>
<span class="line"><span>│  3. Model analyzes pixels, identifies UI elements   │</span></span>
<span class="line"><span>│     → &quot;search box is at (756, 342)&quot;                 │</span></span>
<span class="line"><span>│  4. Calls left_click { coordinate: [756, 342] }     │</span></span>
<span class="line"><span>│  5. Calls type { text: &quot;search query&quot; }             │</span></span>
<span class="line"><span>│  6. Calls screenshot again → verify → next step...  │</span></span>
<span class="line"><span>└───────────────┬────────────────────────────────────┘</span></span>
<span class="line"><span>                │ MCP Tool Call</span></span>
<span class="line"><span>                ▼</span></span>
<span class="line"><span>┌────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  TypeScript Tool Layer (vendor/computer-use-mcp)    │</span></span>
<span class="line"><span>│  - Security checks (app allowlist, TCC permissions) │</span></span>
<span class="line"><span>│  - Coordinate transformation                        │</span></span>
<span class="line"><span>│  - Tool dispatch → executor                         │</span></span>
<span class="line"><span>└───────────────┬────────────────────────────────────┘</span></span>
<span class="line"><span>                │ callPythonHelper()</span></span>
<span class="line"><span>                ▼</span></span>
<span class="line"><span>┌────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Python Bridge                                      │</span></span>
<span class="line"><span>│  macOS: runtime/mac_helper.py                       │</span></span>
<span class="line"><span>│  Windows: runtime/win_helper.py                     │</span></span>
<span class="line"><span>│  pyautogui.click(756, 342)   ← mouse control        │</span></span>
<span class="line"><span>│  mss.grab(monitor)           ← screenshot            │</span></span>
<span class="line"><span>│  NSWorkspace / win32gui      ← app management        │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Key</strong>: Coordinate analysis is performed entirely by the model&#39;s vision capabilities — it &quot;sees&quot; the screenshot like a human sees a screen, identifying buttons, text fields, and other UI elements directly from pixels.</p><hr><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><h3 id="1-install-dependencies" tabindex="-1">1. Install dependencies <a class="header-anchor" href="#1-install-dependencies" aria-label="Permalink to &quot;1. Install dependencies&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h3 id="2-ensure-python-3-is-available" tabindex="-1">2. Ensure Python 3 is available <a class="header-anchor" href="#2-ensure-python-3-is-available" aria-label="Permalink to &quot;2. Ensure Python 3 is available&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # &gt;= 3.8 required</span></span></code></pre></div><blockquote><p>Python dependencies are <strong>automatically installed</strong> into <code>.runtime/venv/</code> on first Computer Use invocation.</p></blockquote><h3 id="3-grant-macos-permissions" tabindex="-1">3. Grant macOS permissions <a class="header-anchor" href="#3-grant-macos-permissions" aria-label="Permalink to &quot;3. Grant macOS permissions&quot;">​</a></h3><p><strong>Accessibility:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">open</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-apple.systempreferences:com.apple.preference.security?Privacy_Accessibility&quot;</span></span></code></pre></div><p>Add your <strong>terminal app</strong> (iTerm, Terminal, Ghostty, etc.) to the allow list.</p><p><strong>Screen Recording:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">open</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-apple.systempreferences:com.apple.preference.security?Privacy_ScreenCapture&quot;</span></span></code></pre></div><p>Add your terminal app as well. You may need to <strong>restart your terminal</strong> after granting permission.</p><h3 id="4-start" tabindex="-1">4. Start <a class="header-anchor" href="#4-start" aria-label="Permalink to &quot;4. Start&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./bin/claude-haha</span></span></code></pre></div><h3 id="5-use" tabindex="-1">5. Use <a class="header-anchor" href="#5-use" aria-label="Permalink to &quot;5. Use&quot;">​</a></h3><p>Just ask in natural language:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Take a screenshot of my desktop</span></span>
<span class="line"><span>&gt; Open Safari and search for something</span></span>
<span class="line"><span>&gt; Type &quot;hello&quot; in the text editor</span></span></code></pre></div><h3 id="disable-computer-use" tabindex="-1">Disable Computer Use <a class="header-anchor" href="#disable-computer-use" aria-label="Permalink to &quot;Disable Computer Use&quot;">​</a></h3><p>If you only want the regular Coding Agent and do not want to expose <code>computer-use</code> MCP tools, disable it with either command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude-haha</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-computer-use</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CLAUDE_COMPUTER_USE_ENABLED</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> claude-haha</span></span></code></pre></div><p>You can also write the global config file at <code>~/.claude/cc-haha/computer-use-config.json</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The desktop Settings &gt; Computer Use switch writes the same config. Once disabled, new sessions will not inject the dynamic <code>computer-use</code> MCP server or add its desktop-control tools to <code>allowedTools</code>.</p><hr><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mechanism</th><th>Description</th></tr></thead><tbody><tr><td><strong>App allowlist</strong></td><td>Each session requires explicit authorization for which apps Claude can interact with</td></tr><tr><td><strong>Concurrency lock</strong></td><td>Only one Claude session can use Computer Use at a time (file lock)</td></tr><tr><td><strong>Clipboard guard</strong></td><td>Original clipboard content is saved and restored when typing via clipboard</td></tr><tr><td><strong>Sensitive action gates</strong></td><td>System keyboard shortcuts require additional authorization</td></tr></tbody></table><blockquote><p>Note: Since we replaced the native modules with Python bridge, the global Escape hotkey abort and auto-hide features from the original implementation are not available. Use <code>Ctrl+C</code> to abort instead.</p></blockquote><hr><h2 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>CLAUDE_COMPUTER_USE_ENABLED</code></td><td><code>1</code></td><td>Set to <code>0</code> to disable Computer Use</td></tr><tr><td><code>CLAUDE_COMPUTER_USE_COORDINATE_MODE</code></td><td><code>pixels</code></td><td>Coordinate mode: <code>pixels</code> or <code>normalized_0_100</code></td></tr><tr><td><code>CLAUDE_COMPUTER_USE_CLIPBOARD_PASTE</code></td><td><code>1</code></td><td>Enable clipboard-based text input</td></tr><tr><td><code>CLAUDE_COMPUTER_USE_MOUSE_ANIMATION</code></td><td><code>1</code></td><td>Enable mouse animation</td></tr><tr><td><code>CLAUDE_COMPUTER_USE_DEBUG</code></td><td><code>0</code></td><td>Debug mode</td></tr></tbody></table><hr><h2 id="technical-architecture" tabindex="-1">Technical Architecture <a class="header-anchor" href="#technical-architecture" aria-label="Permalink to &quot;Technical Architecture&quot;">​</a></h2><h3 id="gate-bypass" tabindex="-1">Gate Bypass <a class="header-anchor" href="#gate-bypass" aria-label="Permalink to &quot;Gate Bypass&quot;">​</a></h3><p>The official Claude Code gates Computer Use behind three layers:</p><table tabindex="0"><thead><tr><th>Layer</th><th>Original Mechanism</th><th>Our Approach</th></tr></thead><tbody><tr><td>Compile-time</td><td><code>feature(&#39;CHICAGO_MCP&#39;)</code> (Bun macro)</td><td>Replaced with <code>true</code></td></tr><tr><td>Subscription</td><td><code>hasRequiredSubscription()</code> (Max/Pro only)</td><td><code>getChicagoEnabled()</code> returns <code>true</code> directly</td></tr><tr><td>Remote config</td><td>GrowthBook <code>tengu_malort_pedway</code></td><td>Same — no remote dependency</td></tr><tr><td>Default-disabled</td><td><code>isDefaultDisabledBuiltin(&#39;computer-use&#39;)</code></td><td>Returns <code>false</code></td></tr></tbody></table><h3 id="python-bridge" tabindex="-1">Python Bridge <a class="header-anchor" href="#python-bridge" aria-label="Permalink to &quot;Python Bridge&quot;">​</a></h3><p>On first invocation, the bridge automatically:</p><ol><li>Creates a Python virtual environment (<code>.runtime/venv/</code>)</li><li>Installs pip</li><li>Installs dependencies (<code>mss</code>, <code>Pillow</code>, <code>pyautogui</code>, <code>pyobjc-*</code>)</li><li>Validates via SHA256 hash (only reinstalls when <code>requirements.txt</code> changes)</li></ol><hr><h2 id="approaches-we-tried" tabindex="-1">Approaches We Tried <a class="header-anchor" href="#approaches-we-tried" aria-label="Permalink to &quot;Approaches We Tried&quot;">​</a></h2><h3 id="approach-1-extract-native-node-modules-from-claude-code-binary-" tabindex="-1">Approach 1: Extract native .node modules from Claude Code binary ❌ <a class="header-anchor" href="#approach-1-extract-native-node-modules-from-claude-code-binary-" aria-label="Permalink to &quot;Approach 1: Extract native .node modules from Claude Code binary ❌&quot;">​</a></h3><p>Extracted <code>computer-use-swift.node</code> and <code>computer-use-input.node</code> from the installed Claude Code Mach-O binary. Synchronous methods worked, but async Swift methods (screenshot) hung due to N-API async incompatibility between Bun versions.</p><h3 id="approach-2-create-empty-stub-packages-" tabindex="-1">Approach 2: Create empty stub packages ❌ <a class="header-anchor" href="#approach-2-create-empty-stub-packages-" aria-label="Permalink to &quot;Approach 2: Create empty stub packages ❌&quot;">​</a></h3><p>Stub packages allowed compilation but provided no actual functionality.</p><h3 id="approach-3-python-bridge--current" tabindex="-1">Approach 3: Python Bridge ✅ (current) <a class="header-anchor" href="#approach-3-python-bridge--current" aria-label="Permalink to &quot;Approach 3: Python Bridge ✅ (current)&quot;">​</a></h3><p>Replaced all native module calls with Python subprocess calls via <code>callPythonHelper()</code>. Zero binary dependencies, auto-bootstrapping, full functionality on any macOS.</p><hr><h2 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Limitation</th><th>Description</th></tr></thead><tbody><tr><td>Linux not adapted</td><td>Linux needs <code>wmctrl</code> + <code>xdotool</code> style platform integration</td></tr><tr><td>No global Escape abort</td><td>Original used CGEventTap; use <code>Ctrl+C</code> instead</td></tr><tr><td>No auto-hide windows</td><td>Original&#39;s <code>prepareDisplay</code> relied on Swift</td></tr><tr><td>Slightly higher latency</td><td>~100ms Python process startup overhead per call</td></tr></tbody></table><hr><h2 id="references-and-credits" tabindex="-1">References and Credits <a class="header-anchor" href="#references-and-credits" aria-label="Permalink to &quot;References and Credits&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Project</th><th>License</th><th>Contribution</th></tr></thead><tbody><tr><td><a href="https://github.com/wimi321/macos-computer-use-skill" target="_blank" rel="noreferrer">wimi321/macos-computer-use-skill</a></td><td>MIT</td><td>Python bridge architecture, <code>mac_helper.py</code> runtime, executor adaptation</td></tr><tr><td><a href="https://github.com/domdomegg/computer-use-mcp" target="_blank" rel="noreferrer">domdomegg/computer-use-mcp</a></td><td>MIT</td><td>Independent Computer Use MCP server (nut.js based), used as reference</td></tr><tr><td><a href="https://github.com/paoloanzn/free-code" target="_blank" rel="noreferrer">paoloanzn/free-code</a></td><td>-</td><td>Feature flag system analysis</td></tr><tr><td><a href="https://github.com/oboard/claude-code-rev" target="_blank" rel="noreferrer">oboard/claude-code-rev</a></td><td>-</td><td>Early leaked source restoration, stub package reference</td></tr></tbody></table><h3 id="underlying-libraries" tabindex="-1">Underlying Libraries <a class="header-anchor" href="#underlying-libraries" aria-label="Permalink to &quot;Underlying Libraries&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Library</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="https://github.com/asweigart/pyautogui" target="_blank" rel="noreferrer">pyautogui</a></td><td>Mouse and keyboard control</td></tr><tr><td><a href="https://github.com/BoboTiG/python-mss" target="_blank" rel="noreferrer">mss</a></td><td>Screenshot capture</td></tr><tr><td><a href="https://github.com/python-pillow/Pillow" target="_blank" rel="noreferrer">Pillow</a></td><td>Image processing and compression</td></tr><tr><td><a href="https://github.com/ronaldoussoren/pyobjc" target="_blank" rel="noreferrer">pyobjc</a></td><td>macOS Cocoa/Quartz framework bindings</td></tr></tbody></table>`,76)])])}const b=t(n,[["render",i]]);export{u as __pageData,b as default};
